svg.script:
// 1. 尾巴晃动
const tail = document.getElementById('tail');
let tailAngle = 0;
let tailDirection = 1;
function animateTail() {
  tailAngle += 0.5 * tailDirection;
  if (tailAngle > 5 || tailAngle < -5) tailDirection *= -1;
  tail.setAttribute('transform', `rotate(${tailAngle} 200 450)`);
  requestAnimationFrame(animateTail);
}

// 2. 外鳃摆动
const gillLeft = document.getElementById('gill-left');
const gillRight = document.getElementById('gill-right');
let gillAngle = 0;
let gillDirection = 1;
function animateGills() {
  gillAngle += 0.3 * gillDirection;
  if (gillAngle > 3 || gillAngle < -3) gillDirection *= -1;
  gillLeft.setAttribute('transform', `rotate(${gillAngle} 300 250)`);
  gillRight.setAttribute('transform', `rotate(${-gillAngle} 570 250)`);
  requestAnimationFrame(animateGills);
}

// 3. 眨眼动画
const eyeLeftInner = document.getElementById('eye-left-inner');
const eyeRightInner = document.getElementById('eye-right-inner');
let isBlinking = false;
function blink() {
  if (isBlinking) return;
  isBlinking = true;
  eyeLeftInner.setAttribute('r', 5);
  eyeRightInner.setAttribute('r', 5);
  setTimeout(() => {
    eyeLeftInner.setAttribute('r', 32);
    eyeRightInner.setAttribute('r', 32);
    isBlinking = false;
  }, 200);
  setTimeout(blink, Math.random() * 3000 + 3000);
}

// 4. 吐泡泡 + 嘴型适配
const mouth = document.getElementById('mouth');
const bubbleContainer = document.getElementById('bubble-container');
const smileMouth = "M420 420 Q450 445 480 420"; // 微笑嘴型
const openMouth = "M420 420 Q450 460 480 420";    // 张开嘴型

function openMouthAndBubble() {
  // 第一步：张开嘴巴
  mouth.setAttribute('d', openMouth);

  // 第二步：延迟200ms后生成泡泡
  setTimeout(() => {
    const bubble = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
    const size = Math.random() * 15 + 10;
    const x = Math.random() * 60 + 420;
    const y = 440;

    bubble.setAttribute('cx', x);
    bubble.setAttribute('cy', y);
    bubble.setAttribute('r', size);
    bubble.setAttribute('fill', 'url(#bubbleGrad)');
    bubble.setAttribute('stroke', '#e0f7fa');
    bubble.setAttribute('stroke-width', 2);
    bubbleContainer.appendChild(bubble);

    // 泡泡上浮动画
    let bubbleY = y;
    function moveBubble() {
      bubbleY -= 1;
      bubble.setAttribute('cy', bubbleY);
      const opacity = 1 - (bubbleY - 200) / 240;
      bubble.setAttribute('opacity', opacity);

      if (bubbleY > 200) {
        requestAnimationFrame(moveBubble);
      } else {
        bubbleContainer.removeChild(bubble);
      }
    }
    requestAnimationFrame(moveBubble);
  }, 200);

  // 第三步：再延迟300ms后闭上嘴巴（恢复微笑）
  setTimeout(() => {
    mouth.setAttribute('d', smileMouth);
  }, 500);

  // 随机5-10秒后再次吐泡泡
  setTimeout(openMouthAndBubble, Math.random() * 5000 + 5000);
}

// 启动所有动画
animateTail();
animateGills();
blink();
openMouthAndBubble();
